from pydantic import BaseModel, Field, field_validator, model_validator
from typing import Literal

class SearchArgs(BaseModel):
    query: str = Field(min_length=1, max_length=500,
                       description="Search query string")
    top_k: int = Field(default=5, ge=1, le=50,
                       description="Number of results to return")
    mode: Literal["semantic", "keyword", "hybrid"] = "semantic"

    @field_validator("query")
    @classmethod
    def strip_query(cls, v: str) -> str:
        # Normalise whitespace from LLM output
        return " ".join(v.split())

    @model_validator(mode="after")
    def check_consistency(self) -> "SearchArgs":
        if self.mode == "keyword" and self.top_k > 20:
            raise ValueError("keyword mode supports at most top_k=20")
        return self

# Lax coercion: "10" str → int 10
args = SearchArgs.model_validate({"query": "  pydantic  ", "top_k": "10"})
print(args.query)   # "pydantic"  (stripped)
print(args.top_k)   # 10         (coerced from str)

