from __future__ import annotations
from pydantic import BaseModel, Field, ValidationError
from typing import Any
import json


# ── Model definitions ────────────────────────────────────────────────────

class WebSearchArgs(BaseModel):
    query: str = Field(min_length=1, description="Search terms")
    top_k: int = Field(default=5, ge=1, le=20, description="Result count")
    safe: bool = True


class WebSearchResult(BaseModel):
    results: list[str]
    total_hits: int


# ── JSON Schema for the LLM (single source of truth) ───────────────────

def tool_schema(model: type[BaseModel], name: str, description: str) -> dict:
    return {
        "type": "function",
        "function": {
            "name": name,
            "description": description,
            "parameters": model.model_json_schema(),
        },
    }

schema = tool_schema(WebSearchArgs, "web_search", "Search the web for information")
# Pass schema to LLM in tools=[] parameter


# ── Dispatch with validation ─────────────────────────────────────────────

def dispatch(tool_name: str, raw_args: dict[str, Any]) -> dict[str, Any]:
    REGISTRY: dict[str, tuple[type[BaseModel], Any]] = {
        "web_search": (WebSearchArgs, _run_web_search),
    }

    if tool_name not in REGISTRY:
        return {"error": f"Unknown tool: {tool_name}"}

    ArgsModel, handler = REGISTRY[tool_name]

    try:
        args = ArgsModel.model_validate(raw_args)
    except ValidationError as exc:
        # Return structured error the LLM can act on
        return {
            "error": "validation_failed",
            "details": exc.errors(include_url=False),
        }

    raw_result = handler(args)
    return WebSearchResult.model_validate(raw_result).model_dump()


def _run_web_search(args: WebSearchArgs) -> dict:
    # Real implementation would call a search API
    return {
        "results": [f"Result {i} for '{args.query}'" for i in range(1, args.top_k + 1)],
        "total_hits": args.top_k,
    }


# ── Usage ────────────────────────────────────────────────────────────────

result = dispatch("web_search", {"query": "pydantic schema validation", "top_k": 3})
print(json.dumps(result, indent=2))

# Illustrative excerpt from a production agent tool executor
# (dependencies: pydantic, anthropic)

from __future__ import annotations
import json
from pydantic import BaseModel, Field, ValidationError
from typing import Any


class ToolInput(BaseModel):
    """Base class — each tool subclasses this."""
    class Config:
        extra = "forbid"          # reject unexpected fields from LLM


class CalculatorInput(ToolInput):
    expression: str = Field(
        description="A Python arithmetic expression, e.g. '2 ** 10 / 4'"
    )


class CalculatorOutput(BaseModel):
    result: float
    expression: str


def run_calculator(args: CalculatorInput) -> CalculatorOutput:
    # In production: safe expression parser, not eval
    # Using eval here for illustration only in a sandboxed context
    result = float(eval(args.expression, {"__builtins__": {}}, {}))  # nosec
    return CalculatorOutput(result=result, expression=args.expression)


def execute_tool(tool_name: str, tool_input_json: str) -> dict[str, Any]:
    """
    Called with the raw content of an Anthropic tool_use block.
    Returns either a validated result dict or a tool_error dict.
    """
    TOOLS = {"calculator": (CalculatorInput, run_calculator)}

    if tool_name not in TOOLS:
        return {"type": "tool_error", "error": f"Unknown tool: {tool_name}"}

    InputModel, handler = TOOLS[tool_name]

    # Decode JSON string emitted by the model
    try:
        raw = json.loads(tool_input_json)
    except json.JSONDecodeError as exc:
        return {"type": "tool_error", "error": f"Malformed JSON: {exc}"}

    # Validate input against schema
    try:
        args = InputModel.model_validate(raw)
    except ValidationError as exc:
        # Structured error the model can understand and self-correct
        return {
            "type": "tool_error",
            "error": "Invalid tool arguments",
            "field_errors": [
                {"field": ".".join(str(l) for l in e["loc"]), "message": e["msg"]}
                for e in exc.errors(include_url=False)
            ],
        }

    output = handler(args)
    return {"type": "tool_result", **output.model_dump()}


# --- Simulate a tool call from the model ---
result = execute_tool("calculator", '{"expression": "2 ** 10 / 4"}')
print(result)
# {'type': 'tool_result', 'result': 256.0, 'expression': '2 ** 10 / 4'}

error = execute_tool("calculator", '{"expression": ""}')
print(error)
# {'type': 'tool_error', 'error': 'Invalid tool arguments', 'field_errors': [...]}

